	enc := json.NewEncoder(f)
	enc.SetEscapeHTML(false)
	for _, b := range beads {
		data, err := marshalBead(b)
		if err != nil {
			f.Close()
			os.Remove(tmp)
			return fmt.Errorf("bead: marshal: %w", err)
		}
		if _, err := f.Write(data); err != nil {
			f.Close()
			os.Remove(tmp)
			return fmt.Errorf("bead: write: %w", err)
		}
		if _, err := f.WriteString("\n"); err != nil {
			f.Close()
			os.Remove(tmp)
